Here's a well-structured MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays forever
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(delay: Timeout.InfiniteTimeSpan);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Cancel immediately
        cts.Cancel();

        // Act & Assert
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_IsCancelled()
    {
        // Arrange — handler that delays longer than our token allows
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert — the 100ms token fires before the 30s delay
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    /// <summary>Minimal HttpMessageHandler for deterministic tests.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response)
        {
            _response = response;
            _delay = TimeSpan.Zero;
        }

        public FakeHandler(TimeSpan delay)
        {
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(_delay, cancellationToken);
            return _response ?? new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly if it hangs |
| `Assert.ThrowsExactlyAsync` | Verifies exact exception type with a clear failure message |
| `Assert.ThrowsAsync` | Matches `OperationCanceledException` *or* derived `TaskCanceledException` |
| `FakeHandler` | Avoids real HTTP; controls delay for cancellation/timeout tests |
| `sealed` test class + `sealed` handler | Performance and design clarity |

For the cancellation tests, `Assert.ThrowsAsync<OperationCanceledException>` (not `ThrowsExactly`) is intentional — `HttpClient` may throw either `OperationCanceledException` or the derived `TaskCanceledException` depending on the runtime.
